import{_ as t,o,c as a,ag as n}from"./chunks/framework.DZKik_R9.js";const m=JSON.parse('{"title":"Solution d’A/B test — introduction","description":"","frontmatter":{},"headers":[],"relativePath":"solution/intro.md","filePath":"solution/intro.md"}'),r={name:"solution/intro.md"};function s(d,e,i,l,c,u){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="solution-d-a-b-test-—-introduction" tabindex="-1">Solution d’A/B test — introduction <a class="header-anchor" href="#solution-d-a-b-test-—-introduction" aria-label="Permalink to &quot;Solution d’A/B test — introduction&quot;">​</a></h1><h2 id="role" tabindex="-1">Rôle <a class="header-anchor" href="#role" aria-label="Permalink to &quot;Rôle&quot;">​</a></h2><p>Le dépôt <strong><code>abtest-solution</code></strong> fournit le moteur, l’<strong>API</strong>, l’<strong>UI</strong> d’administration et le <strong>remote</strong> Module Federation consommable par un site hôte (ex. labo <code>small-webserver</code>).</p><h2 id="structure-du-monorepo" tabindex="-1">Structure du monorepo <a class="header-anchor" href="#structure-du-monorepo" aria-label="Permalink to &quot;Structure du monorepo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Rôle</th></tr></thead><tbody><tr><td><code>apps/api</code></td><td>Express : CRUD campagnes / segments, <code>POST /api/evaluate</code>, <code>GET /api/consent-config</code> ; persistance via <code>storage-fs</code> (voir <a href="./../reference/api-overview">Aperçu de l’API</a>).</td></tr><tr><td><code>apps/remote</code></td><td>Bundle Module Federation : contexte navigateur, injection des variantes (<code>VITE_REMOTE_PORT</code> en dev).</td></tr><tr><td><code>apps/ui</code></td><td>Interface d’administration React (<code>VITE_UI_PORT</code> en dev).</td></tr><tr><td><code>packages/core</code></td><td>Modèle métier, évaluation des règles, bucketing, consentement.</td></tr><tr><td><code>packages/storage-fs</code></td><td>Lecture / écriture JSON + validation (Zod) sous la racine données.</td></tr><tr><td><code>abtest-campaigns-segments/</code></td><td>Submodule : campagnes, segments, <code>consent-config.json</code> optionnel (<a href="./campaigns-segments/">introduction</a>).</td></tr></tbody></table><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p><a href="./../install/abtest-solution">Installer la solution d’A/B test</a></p><h2 id="dependance-donnees" tabindex="-1">Dépendance données <a class="header-anchor" href="#dependance-donnees" aria-label="Permalink to &quot;Dépendance données&quot;">​</a></h2><p>Les définitions métier sont dans <strong><code>abtest-campaigns-segments</code></strong>, sous <code>abtest-solution/abtest-campaigns-segments/</code>. Voir <a href="./campaigns-segments/">Campagnes et segments</a> et <a href="./../reference/submodules">Submodules</a>.</p><h2 id="module-federe-sur-un-site-quelconque" tabindex="-1">Module fédéré sur un site quelconque <a class="header-anchor" href="#module-federe-sur-un-site-quelconque" aria-label="Permalink to &quot;Module fédéré sur un site quelconque&quot;">​</a></h2><ol><li>Builder et déployer <code>apps/remote</code> sur une URL stable.</li><li>Configurer Module Federation côté hôte.</li><li>Utiliser l’API / composants exposés pour évaluer et afficher.</li></ol><p>Détail : <a href="./module-federation">Module Federation et intégration hôte</a>.</p><h2 id="suite" tabindex="-1">Suite <a class="header-anchor" href="#suite" aria-label="Permalink to &quot;Suite&quot;">​</a></h2><ul><li><a href="./consent">Consentement</a></li><li><a href="./campaigns-segments/">Campagnes et segments</a></li><li><a href="./../reference/api-overview">Aperçu de l’API</a></li><li><a href="./../reference/ports-and-env">Ports et variables</a></li></ul>',14)])])}const h=t(r,[["render",s]]);export{m as __pageData,h as default};
